-- create "contract_supplier_histories" table
CREATE TABLE "public"."contract_supplier_histories" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "history_id" uuid NOT NULL,
  "contract_id" uuid NOT NULL,
  "operation_type" character varying NOT NULL,
  "changed_at" timestamptz NOT NULL,
  "changed_by" uuid NULL,
  "snapshot" jsonb NULL,
  "diff" jsonb NULL,
  PRIMARY KEY ("id")
);
-- create index "contract_supplier_histories_history_id_key" to table: "contract_supplier_histories"
CREATE UNIQUE INDEX "contract_supplier_histories_history_id_key" ON "public"."contract_supplier_histories" ("history_id");
-- create index "contract_supplier_history_changed_at" to table: "contract_supplier_histories"
CREATE INDEX "contract_supplier_history_changed_at" ON "public"."contract_supplier_histories" ("changed_at");
-- create index "contract_supplier_history_contract_id" to table: "contract_supplier_histories"
CREATE INDEX "contract_supplier_history_contract_id" ON "public"."contract_supplier_histories" ("contract_id");
-- create "contract_suppliers" table
CREATE TABLE "public"."contract_suppliers" (
  "id" uuid NOT NULL,
  "supplier_id" uuid NOT NULL,
  "contract_number" character varying NOT NULL,
  "vat_flag" boolean NOT NULL DEFAULT false,
  "signed_date" date NOT NULL,
  "amount" numeric(14,2) NOT NULL,
  "amount_currency" numeric(14,2) NULL,
  "currency" character varying NULL,
  "balance_at_year_end" numeric(14,2) NULL,
  "amendment_number" character varying NULL,
  "amendment_date" date NULL,
  "amendment_amount" numeric(14,2) NULL,
  "total_with_amendment" numeric(14,2) NOT NULL,
  "remaining_amount" numeric(14,2) NOT NULL,
  "is_active" boolean NOT NULL DEFAULT true,
  "created_at" timestamptz NOT NULL DEFAULT now(),
  "updated_at" timestamptz NOT NULL DEFAULT now(),
  PRIMARY KEY ("id")
);
-- create index "contract_supplier_contract_number" to table: "contract_suppliers"
CREATE INDEX "contract_supplier_contract_number" ON "public"."contract_suppliers" ("contract_number");
-- create index "contract_supplier_supplier_id" to table: "contract_suppliers"
CREATE INDEX "contract_supplier_supplier_id" ON "public"."contract_suppliers" ("supplier_id");
